select * from customer_behaviour;

alter table customer_behaviour
drop column MyUnknownColumn;

-- Q1. What is the total revenue generated by male vs female customers? --
select gender, sum(purchase_amount) as total_revenue
from customer_behaviour
group by gender;

-- Q2. Which customers used a discount but still spent more than the average purchase ammount? --
select customer_id, purchase_amount
from customer_behaviour
where discount_applied = "Yes" and 
purchase_amount > (select avg(purchase_amount) from customer_behaviour);

-- Q3. Which are the top 5 product with the highest average review rating?
select item_purchased, round(avg(review_rating),2) as avg_review_rating
from customer_behaviour
group by item_purchased
order by avg_review_rating desc limit 5;

-- Q4. Compare the average purchase amount between Standard and Express Shipping?
select shipping_type, avg(purchase_amount) as avg_purchase_amount
from customer_behaviour
group by shipping_type
having shipping_type = "Express" or shipping_type = "Standard";

-- Q5. Do subscribed customers spend more? compare average spend and total revenue of both?
select subscription_status, count(*) as total_customers,
avg(purchase_amount) as avg_spending, 
sum(purchase_amount) as total_revenue
from customer_behaviour
group by subscription_status;

-- Q6 which top 5 products have the highest percentage of purchases with discount applied?
select item_purchased,
(count(*)/(select count(*) from customer_behaviour))*100 as contribution
from customer_behaviour
where discount_applied = "Yes"
group by item_purchased
order by contribution desc limit 5;

-- Q7 Segment into new, returning, and loyal based on thier total number of previous 
-- purchases and show the count of each segment?
select customer_segment, count(*) as customers
from (select customer_id, previous_purchases,
case when previous_purchases = 1 then "new"
when previous_purchases between 1 and 10 then "returning"
else "loyal" end as customer_segment
from customer_behaviour) as t
group by customer_segment;

-- Q8 What are the top 3 most purchased products within each catagory?
select category, item_purchased, count(*) as purchases
from customer_behaviour
group by category, item_purchased
order by category, purchases desc;

-- Q9 Are customers who are repeat buyers (more than 5 previous purchases) also likely to subscribe?
select subscription_status, count(*) as total_customers from customer_behaviour
where previous_purchases > 5
group by subscription_status;

-- Q10 What is the revenue contribution of each age group?
select age_group, count(*) as total_customers, sum(purchase_amount) as total_revenue,
round(sum(purchase_amount)/(select sum(purchase_amount) from customer_behaviour)*100,2) as contribution
from customer_behaviour
group by age_group
order by contribution desc;














































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































